def read_config(filepath):
    try:
        with open(filepath, "r") as f:
            return f.read()
    except FileNotFoundError:
        print(f"Config file not found: {filepath}")
        return None
    except PermissionError:
        print(f"No read permission for: {filepath}")
        return None

def parse_integer(value):
    try:
        return int(value)
    except (ValueError, TypeError):
        return None   # Return a sentinel value indicating failure

import time

def call_api_with_retry(prompt, max_retries=3):
    for attempt in range(max_retries):
        try:
            return llm_client.complete(prompt)
        except RateLimitError:
            wait = 2 ** attempt   # Exponential backoff: 1s, 2s, 4s
            print(f"Rate limited. Retrying in {wait}s...")
            time.sleep(wait)
        except APIError as e:
            print(f"API error on attempt {attempt + 1}: {e}")
            if attempt == max_retries - 1:
                raise   # Give up after final attempt
    return None

# BAD — swallows all errors including bugs
try:
    do_something()
except Exception:
    pass   # Silent failure is the hardest kind to debug

# GOOD — catch specifically, or at minimum log what you catch
try:
    do_something()
except Exception as e:
    logger.error(f"Unexpected error: {e}", exc_info=True)
    raise

# BAD — the original cause is lost
try:
    connect()
except ConnectionError:
    raise RuntimeError("Connection failed")   # No "from" — original traceback gone

# GOOD — chain exceptions to preserve context
try:
    connect()
except ConnectionError as e:
    raise RuntimeError("Connection failed") from e

